mapper.insert:
INSERT INTO post_comments (
    post_id, user_id, content, parent_id
) VALUES (
    #{postId}, #{userId}, #{content}, #{parentId}
)

mapper.select:
SELECT c.*, u.username, u.real_name, u.avatar,
       CASE WHEN pcl.user_id IS NULL THEN FALSE ELSE TRUE END AS liked_by_current_user
FROM post_comments c
LEFT JOIN users u ON c.user_id = u.id
LEFT JOIN post_comment_likes pcl ON c.id = pcl.comment_id AND pcl.user_id = #{currentUserId}
WHERE c.id = #{id}
